create table player_contracts (
    contract_id     number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    player_id       number not null enable,
    start_date      date not null enable,
    end_date        date not null enable,
    salary_amount   number(12, 2) not null enable,
    bonus_amount    number(12, 2) default 0 not null enable,
    guaranteed_flag char(1 byte) default 'Y' not null enable,
    contract_status varchar2(20 byte) default 'ACTIVE' not null enable
);

alter table player_contracts
    add constraint contracts_dates_ck check ( end_date >= start_date ) enable;

alter table player_contracts
    add constraint contracts_guaranteed_ck
        check ( guaranteed_flag in ( 'Y', 'N' ) ) enable;

alter table player_contracts
    add constraint contracts_status_ck
        check ( contract_status in ( 'ACTIVE', 'EXPIRED', 'TERMINATED' ) ) enable;

alter table player_contracts
    add constraint player_contracts_pk primary key ( contract_id )
        using index enable;


